function is_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;} function is_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;} function is_c($v){return strtoupper(trim((string)$v));} function is_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
