function is_next_no($year){global $db;$year=(int)$year>0?(int)$year:(int)date('Y');$r=$db->fetch("SELECT interview_no FROM erp_interview_schedule WHERE interview_no LIKE ? ORDER BY interview_no DESC LIMIT 1",array('INT-'.$year.'-%'));$n=1;if($r&&preg_match('/-(\d+)$/',$r->interview_no,$m))$n=(int)$m[1]+1;return 'INT-'.$year.'-'.str_pad($n,3,'0',STR_PAD_LEFT);}
function is_row($id){global $db;return $db->fetch("SELECT i.*,a.applicant_no,a.applicant_name,a.applicant_status,v.vacancy_no,v.vacancy_title,rec.employee_no recruiter_no,rec.full_name recruiter_name,pri.employee_no primary_no,pri.full_name primary_name,hr.employee_no hr_no,hr.full_name hr_name,tech.employee_no tech_no,tech.full_name tech_name,hm.employee_no manager_no,hm.full_name manager_name FROM erp_interview_schedule i LEFT JOIN erp_applicant_data a ON a.id=i.applicant_id LEFT JOIN erp_job_vacancy v ON v.id=i.vacancy_id LEFT JOIN erp_employee_master rec ON rec.id=i.recruiter_employee_id LEFT JOIN erp_employee_master pri ON pri.id=i.primary_interviewer_employee_id LEFT JOIN erp_employee_master hr ON hr.id=i.hr_interviewer_employee_id LEFT JOIN erp_employee_master tech ON tech.id=i.technical_interviewer_employee_id LEFT JOIN erp_employee_master hm ON hm.id=i.hiring_manager_employee_id WHERE i.id=? LIMIT 1",array((int)$id));}
function is_sync_applicant($applicantId){global $db;if((int)$applicantId<=0)return;$cnt=$db->fetch("SELECT COUNT(*) jml FROM erp_interview_schedule WHERE applicant_id=? AND interview_status<>'CANCELLED'",array((int)$applicantId));if(!$cnt||(int)$cnt->jml===0)return;$r=$db->fetch("SELECT MAX(overall_score) score FROM erp_interview_schedule WHERE applicant_id=? AND interview_status='COMPLETED'",array((int)$applicantId));$score=$r?(float)$r->score:0;$data=array('applicant_status'=>'INTERVIEW','updated_by'=>'admin','updated_at'=>date('Y-m-d H:i:s'));if($score>0){$a=$db->fetch("SELECT screening_score FROM erp_applicant_data WHERE id=? LIMIT 1",array((int)$applicantId));$screen=$a?(float)$a->screening_score:0;$data['interview_score']=$score;$data['final_score']=$screen>0?round(($screen+$score)/2,2):$score;}$db->update('erp_applicant_data',$data,'id',(int)$applicantId);}
function is_payload($r){global $db;$d=(array)$r;$d['applicant_text']=$r->applicant_id?($r->applicant_no.' - '.$r->applicant_name):'';$d['vacancy_text']=$r->vacancy_id?($r->vacancy_no.' - '.$r->vacancy_title):'';$d['recruiter_text']=$r->recruiter_employee_id?($r->recruiter_no.' - '.$r->recruiter_name):'';$d['primary_text']=$r->primary_interviewer_employee_id?($r->primary_no.' - '.$r->primary_name):'';$d['hr_text']=$r->hr_interviewer_employee_id?($r->hr_no.' - '.$r->hr_name):'';$d['technical_text']=$r->technical_interviewer_employee_id?($r->tech_no.' - '.$r->tech_name):'';$d['manager_text']=$r->hiring_manager_employee_id?($r->manager_no.' - '.$r->manager_name):'';$panels=$db->query("SELECT p.*,e.employee_no,e.full_name FROM erp_interview_schedule_panel p LEFT JOIN erp_employee_master e ON e.id=p.interviewer_employee_id WHERE p.interview_id=? ORDER BY p.line_no,p.id",array((int)$r->id));$d['panels']=array();foreach($panels as $p){$a=(array)$p;$a['interviewer_text']=$p->employee_no.' - '.$p->full_name;$d['panels'][]=$a;}return $d;}
function is_export_rows($from,$to,$status,$type,$method,$kw){global $db;$p=array($from,$to);$w=" WHERE i.schedule_date BETWEEN ? AND ? ";if($status!==''){$w.=" AND i.interview_status=? ";$p[]=$status;}if($type!==''){$w.=" AND i.interview_type=? ";$p[]=$type;}if($method!==''){$w.=" AND i.interview_method=? ";$p[]=$method;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (i.interview_no LIKE ? OR a.applicant_name LIKE ? OR v.vacancy_title LIKE ?) ";array_push($p,$like,$like,$like);}return $db->query("SELECT i.*,a.applicant_no,a.applicant_name,v.vacancy_no,v.vacancy_title,pri.employee_no primary_no,pri.full_name primary_name FROM erp_interview_schedule i LEFT JOIN erp_applicant_data a ON a.id=i.applicant_id LEFT JOIN erp_job_vacancy v ON v.id=i.vacancy_id LEFT JOIN erp_employee_master pri ON pri.id=i.primary_interviewer_employee_id $w ORDER BY i.schedule_date DESC,i.start_time DESC",$p);}
$act=isset($_GET['act'])?$_GET['act']:'';$username=is_user();$statuses=array('DRAFT','SCHEDULED','CONFIRMED','COMPLETED','RESCHEDULED','CANCELLED','NO_SHOW');$types=array('HR','TECHNICAL','USER','PANEL','FINAL','ONLINE');$methods=array('ONSITE','ONLINE','PHONE');$recs=array('PENDING','PASS','HOLD','FAIL','REINTERVIEW');
