  if(!$app)is_json('error','Applicant wajib dipilih.');if($date===''||is_p('start_time')===''||is_p('end_time')==='')is_json('error','Tanggal dan jam interview wajib diisi.');if(!in_array($status,$statuses,true))is_json('error','Status tidak valid.');if(!in_array($type,$types,true))is_json('error','Type tidak valid.');if(!in_array($method,$methods,true))is_json('error','Method tidak valid.');if(!in_array($rec,$recs,true))$rec='PENDING';if($db->fetch("SELECT id FROM erp_interview_schedule WHERE interview_no=? AND id<>? LIMIT 1",array($no,$id)))is_json('error','Interview No sudah digunakan.');
