  $data=array('interview_no'=>$no,'applicant_id'=>$app,'vacancy_id'=>$vac,'interview_round'=>max(1,(int)is_p('interview_round',1)),'interview_type'=>$type,'interview_method'=>$method,'interview_status'=>$status,'schedule_date'=>$date,'start_time'=>is_p('start_time'),'end_time'=>is_p('end_time'),'timezone'=>trim(is_p('timezone','Asia/Jakarta')),'location'=>trim(is_p('location')),'meeting_link'=>trim(is_p('meeting_link')),'recruiter_employee_id'=>is_p('recruiter_employee_id')!==''?(int)is_p('recruiter_employee_id'):null,'primary_interviewer_employee_id'=>is_p('primary_interviewer_employee_id')!==''?(int)is_p('primary_interviewer_employee_id'):null,'hr_interviewer_employee_id'=>is_p('hr_interviewer_employee_id')!==''?(int)is_p('hr_interviewer_employee_id'):null,'technical_interviewer_employee_id'=>is_p('technical_interviewer_employee_id')!==''?(int)is_p('technical_interviewer_employee_id'):null,'hiring_manager_employee_id'=>is_p('hiring_manager_employee_id')!==''?(int)is_p('hiring_manager_employee_id'):null,'confirmation_sent'=>is_c(is_p('confirmation_sent','N'))==='Y'?'Y':'N','confirmation_sent_at'=>trim(is_p('confirmation_sent_at'))?:null,'applicant_confirmed'=>is_c(is_p('applicant_confirmed','N'))==='Y'?'Y':'N','applicant_confirmed_at'=>trim(is_p('applicant_confirmed_at'))?:null,'overall_score'=>(float)is_p('overall_score',0),'recommendation'=>$rec,'result_notes'=>trim(is_p('result_notes')),'agenda'=>trim(is_p('agenda')),'preparation_notes'=>trim(is_p('preparation_notes')),'cancellation_reason'=>trim(is_p('cancellation_reason')),'sap_reference'=>trim(is_p('sap_reference')),'remarks'=>trim(is_p('remarks')),'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));
